package main
import "fmt"

type ListNode struct {
	Val  int
	Next *ListNode
}

func reverseKGroup(head *ListNode, k int) *ListNode {


    if head ==nil || k<=1{
        return head
    }

    dummy := &ListNode{Next : head}


    pre := dummy


    for{

        tail := pre

        for i:=0;i<k && tail!=nil;i++{
            tail = tail.Next
        }

        if tail==nil{
            break
        }

        nextGroup := tail.Next

        tail.Next = nil


        headNext := pre.Next //1

        pre.Next = reverseList(headNext)

        headNext.Next = nextGroup


        pre = headNext


    }


    return dummy.Next


}



func reverseList(head *ListNode) *ListNode {
	var pre *ListNode
	current := head

	for current != nil {
		temp := current.Next
		current.Next = pre
		pre = current
		current = temp
	}
	return pre
}



func buildList(nums []int) *ListNode {

        dummy := &ListNode{}
        cur := dummy

        for _, num := range nums {
                cur.Next = &ListNode{Val: num}
                cur = cur.Next
        }

        return dummy.Next
}

func printList(head *ListNode) {

        for head != nil {

                fmt.Print(head.Val)

                if head.Next != nil {
                        fmt.Print(" -> ")
                }

                head = head.Next
        }

        fmt.Println()
}

func main() {

        head := buildList([]int{1, 2, 3, 4, 5, 6, 7, 8})

        k := 3

        newHead := reverseKGroup(head, k)

        printList(newHead)
}
